//! Probabilistic admission for hot distributed-inference mesh routes.
//!
//! This is an execution planner, not a correctness oracle. A `Reuse` decision
//! may select a cached payload or hot lane, but callers still own their normal
//! certificate/hash/result validation before trusting outputs.

use std::collections::{HashMap, VecDeque};

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum MeshProbabilityDecision {
    Reuse,
    Speculate,
    Cover,
    Explore,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct MeshProbabilityPolicy {
    pub min_observations: u64,
    pub min_concentration_bps: u64,
    pub residual_budget: u64,
    pub max_entries: usize,
}

impl Default for MeshProbabilityPolicy {
    fn default() -> Self {
        Self {
            min_observations: 3,
            min_concentration_bps: 8_000,
            residual_budget: 1,
            max_entries: 256,
        }
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct MeshProbabilityWitness {
    pub key: String,
    pub key_hits: u64,
    pub total_mass: u64,
    pub residual_mass: u64,
    pub concentration_bps: u64,
    pub decision: MeshProbabilityDecision,
}

#[derive(Clone, Debug)]
struct MeshProbabilityEntry<V> {
    hits: u64,
    value: Option<V>,
}

#[derive(Clone, Debug)]
pub struct MeshProbabilityAdmission<V> {
    policy: MeshProbabilityPolicy,
    total_mass: u64,
    entries: HashMap<String, MeshProbabilityEntry<V>>,
    insertion_order: VecDeque<String>,
    interpretation_debt: u32,
    harvested_total: u64,
}

impl<V: Clone> MeshProbabilityAdmission<V> {
    pub fn new(policy: MeshProbabilityPolicy) -> Self {
        Self {
            policy,
            total_mass: 0,
            entries: HashMap::new(),
            insertion_order: VecDeque::new(),
            interpretation_debt: 0,
            harvested_total: 0,
        }
    }

    pub fn interpretation_debt(&self) -> u32 {
        self.interpretation_debt
    }

    pub fn increment_debt(&mut self) {
        self.interpretation_debt = self.interpretation_debt.saturating_add(1);
        self.harvested_total = self.harvested_total.saturating_add(1);
    }

    pub fn resolve_debt(&mut self, count: u32) {
        self.interpretation_debt = self.interpretation_debt.saturating_sub(count);
    }

    pub fn harvested_total(&self) -> u64 {
        self.harvested_total
    }

    pub fn observe(&mut self, key: impl Into<String>) -> MeshProbabilityWitness {
        let key = key.into();
        self.total_mass = self.total_mass.saturating_add(1);
        if !self.entries.contains_key(&key) {
            self.evict_if_needed();
            self.insertion_order.push_back(key.clone());
            self.entries.insert(
                key.clone(),
                MeshProbabilityEntry {
                    hits: 0,
                    value: None,
                },
            );
        }

        let entry = self.entries.get_mut(&key).expect("entry inserted");
        entry.hits = entry.hits.saturating_add(1);
        let key_hits = entry.hits;
        self.witness_for(&key, key_hits)
    }

    pub fn get_reusable(&self, witness: &MeshProbabilityWitness) -> Option<V> {
        if witness.decision != MeshProbabilityDecision::Reuse {
            return None;
        }
        self.get_cached(witness)
    }

    pub fn get_admitted_cached(&self, witness: &MeshProbabilityWitness) -> Option<V> {
        if !matches!(
            witness.decision,
            MeshProbabilityDecision::Reuse | MeshProbabilityDecision::Speculate
        ) {
            return None;
        }
        self.get_cached(witness)
    }

    fn get_cached(&self, witness: &MeshProbabilityWitness) -> Option<V> {
        self.entries
            .get(&witness.key)
            .and_then(|entry| entry.value.clone())
    }

    pub fn remember(&mut self, key: &str, value: V) {
        if let Some(entry) = self.entries.get_mut(key) {
            entry.value = Some(value);
        }
    }

    pub fn remember_latent(&mut self, key: &str, value: V) {
        self.remember(key, value);
        self.resolve_debt(1);
    }

    pub fn total_mass(&self) -> u64 {
        self.total_mass
    }

    pub fn len(&self) -> usize {
        self.entries.len()
    }

    fn witness_for(&self, key: &str, key_hits: u64) -> MeshProbabilityWitness {
        let total_mass = self.total_mass.max(key_hits).max(1);
        let residual_mass = total_mass.saturating_sub(key_hits);
        let concentration_bps = key_hits.saturating_mul(10_000) / total_mass;
        let decision = if key_hits < self.policy.min_observations {
            MeshProbabilityDecision::Explore
        } else if residual_mass <= self.policy.residual_budget {
            MeshProbabilityDecision::Reuse
        } else if concentration_bps >= self.policy.min_concentration_bps {
            MeshProbabilityDecision::Speculate
        } else {
            MeshProbabilityDecision::Cover
        };

        MeshProbabilityWitness {
            key: key.to_string(),
            key_hits,
            total_mass,
            residual_mass,
            concentration_bps,
            decision,
        }
    }

    fn evict_if_needed(&mut self) {
        if self.policy.max_entries == 0 {
            self.entries.clear();
            self.insertion_order.clear();
            return;
        }
        while self.entries.len() >= self.policy.max_entries {
            let Some(oldest) = self.insertion_order.pop_front() else {
                break;
            };
            self.entries.remove(&oldest);
        }
    }
}

impl<V: Clone> Default for MeshProbabilityAdmission<V> {
    fn default() -> Self {
        Self::new(MeshProbabilityPolicy::default())
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn repeated_hot_key_reuses_after_cover_is_satisfied() {
        let mut admission = MeshProbabilityAdmission::<Vec<u8>>::new(MeshProbabilityPolicy {
            min_observations: 3,
            min_concentration_bps: 8_000,
            residual_budget: 1,
            max_entries: 16,
        });

        let first = admission.observe("/.aeon/fib20-rf?n=20");
        assert_eq!(first.decision, MeshProbabilityDecision::Explore);
        admission.remember(&first.key, b"cached".to_vec());

        let cold_other = admission.observe("/.aeon/health");
        assert_eq!(cold_other.decision, MeshProbabilityDecision::Explore);

        admission.observe("/.aeon/fib20-rf?n=20");
        let hot = admission.observe("/.aeon/fib20-rf?n=20");

        assert_eq!(hot.key_hits, 3);
        assert_eq!(hot.total_mass, 4);
        assert_eq!(hot.residual_mass, 1);
        assert_eq!(hot.decision, MeshProbabilityDecision::Reuse);
        assert_eq!(admission.get_reusable(&hot), Some(b"cached".to_vec()));
    }

    #[test]
    fn uncovered_residual_requires_cover() {
        let mut admission = MeshProbabilityAdmission::<Vec<u8>>::new(MeshProbabilityPolicy {
            min_observations: 3,
            min_concentration_bps: 9_000,
            residual_budget: 1,
            max_entries: 16,
        });

        admission.observe("hot");
        admission.observe("cold-a");
        admission.observe("cold-b");
        admission.observe("hot");
        let witness = admission.observe("hot");

        assert_eq!(witness.key_hits, 3);
        assert_eq!(witness.total_mass, 5);
        assert_eq!(witness.residual_mass, 2);
        assert_eq!(witness.decision, MeshProbabilityDecision::Cover);
        assert_eq!(admission.get_admitted_cached(&witness), None);
    }

    #[test]
    fn concentrated_mass_admits_cached_speculation() {
        let mut admission = MeshProbabilityAdmission::new(MeshProbabilityPolicy {
            min_observations: 3,
            min_concentration_bps: 7_000,
            residual_budget: 1,
            max_entries: 16,
        });

        let first = admission.observe("hot");
        admission.remember(&first.key, b"hot-payload".to_vec());
        admission.observe("cold-a");
        admission.observe("cold-b");
        admission.observe("hot");
        admission.observe("hot");
        admission.observe("hot");
        let witness = admission.observe("hot");

        assert_eq!(witness.key_hits, 5);
        assert_eq!(witness.total_mass, 7);
        assert_eq!(witness.decision, MeshProbabilityDecision::Speculate);
        assert_eq!(
            admission.get_admitted_cached(&witness),
            Some(b"hot-payload".to_vec())
        );
    }
}
